mapper.select:
SELECT 
FROM `rank` r
LEFT JOIN city c ON c.id = r.city_id
LEFT JOIN category cat ON cat.id = r.category_id
WHERE r.region = #{region} AND r.enabled = TRUE
AND r.city_id = #{cityId}
AND r.category_id = #{categoryId}
AND r.type = #{type}
ORDER BY r.type ASC, r.id DESC

mapper.update:
UPDATE rank_config SET status = 2, effective_to = CURRENT_TIMESTAMP, updated_at = CURRENT_TIMESTAMP
WHERE rank_type = #{rankType} AND region = #{region} AND city_id = #{cityId}
  AND category_id = #{categoryId} AND status = 1 AND id != #{id}

UPDATE rank_config SET status = 1, effective_from = CURRENT_TIMESTAMP, effective_to = NULL,
                       updated_at = CURRENT_TIMESTAMP
WHERE id = #{configId} AND region = #{region}

mapper.select:
SELECT id AS shop_id, name AS shop_name, score, review_count, has_deal, open_now
FROM shop
WHERE region = #{region} AND city_id = #{cityId} AND category_id = #{categoryId}
  AND status = 1 AND is_deleted = FALSE
  AND review_count >= #{minReviewCount} AND score >= #{minScore}

mapper.update:
UPDATE `rank` SET enabled = FALSE, updated_at = CURRENT_TIMESTAMP
WHERE type = #{rankType} AND region = #{region} AND city_id = #{cityId}
  AND category_id = #{categoryId} AND enabled = TRUE
